#include<bits/stdc++.h>
using namespace std;
int ans[200010],v[200010],w[200010],val[200010],c[200010],id[200010],f[200010];
int tot,n,k;
bool vis[20050][20050];
void dfs(int x)
{
    if(x==0)
    {
        for(int i=1;i<=n;i++)
        {
            printf("%d ",ans[i]);
        }
        exit(0);
    }
    while(!vis[tot][x]&&tot)
    {
        tot--;
    }
    x-=v[tot];
    ans[id[tot]]+=w[tot];
    tot--;
    dfs(x);
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&val[i]);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&c[i]);
    }
    scanf("%d",&k);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=c[i];j*=2)
        {
            v[++tot]=j*val[i];
            w[tot]=j;
            id[tot]=i;
            c[i]-=j;
        }
        if(c[i])
        {
            v[++tot]=c[i]*val[i];
            w[tot]=c[i];
            id[tot]=i;
        }
    }
    memset(f,0x3f,sizeof(f));
    f[0]=0;
    for(int i=1;i<=tot;i++)
    {
        for(int j=k;j>=v[i];j--)
        {
            if(f[j-v[i]]+w[i]<f[j])
            {
                f[j]=f[j-v[i]]+w[i];
                vis[i][j]=1;
            }
        }
    }
    printf("%d\n",f[k]);
    dfs(k);
    return 0;
}
